document.addEventListener("DOMContentLoaded",function(){const e=document.querySelectorAll(".filter-btn"),t=document.querySelectorAll(".portfolio-item");e.forEach(n=>{n.addEventListener("click",()=>{const s=n.dataset.filter;e.forEach(e=>e.classList.remove("active")),n.classList.add("active"),t.forEach(e=>{const t=e.dataset.tags;s==="all"||t.includes(s)?e.style.display="block":e.style.display="none"})})})})